using LumiBeauty.Api.DTOs; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Identity; using Microsoft.AspNetCore.Mvc; namespace LumiBeauty.Api.Controllers; [ApiController][Route("api/auth")]public class AuthController:ControllerBase{private readonly UserManager<IdentityUser> _u;private readonly SignInManager<IdentityUser> _s;public AuthController(UserManager<IdentityUser>u,SignInManager<IdentityUser>s){_u=u;_s=s;}[HttpPost("login")]public async Task<IActionResult> Login(LoginRequest r){var u=await _u.FindByEmailAsync(r.Email.Trim());if(u is null||!await _u.IsInRoleAsync(u,"Admin"))return Unauthorized();var x=await _s.PasswordSignInAsync(u,r.Password,false,true);return x.Succeeded?Ok(new{email=u.Email}):Unauthorized();}[Authorize(Roles="Admin")][HttpGet("me")]public IActionResult Me()=>Ok(new{email=User.Identity?.Name});[Authorize(Roles="Admin")][HttpPost("logout")]public async Task<IActionResult> Logout(){await _s.SignOutAsync();return Ok(new{message="Çıkış yapıldı."});}}
